{"type":"user","message":{"role":"user","content":[{"tool_use_id":"tooluse_aXKNac2zybUrYGdIR06YZN","type":"tool_result","content":"=== CODEX CODE ===\n#!/usr/bin/env python3\n\"\"\"\n盘中异动信号检测 - 修订版\n使用真实的mootdx数据源\n\"\"\"\n\nfrom mootdx.quotes import Quotes\nimport pandas as pd\nimport numpy as np\nfrom datetime import datetime, timedelta\nimport warnings\nwarnings.filterwarnings('ignore')\n\ndef get_trading_days_before(end_date, n_days=5):\n    \"\"\"获取指定日期之前的N个交易日（简化版本）\"\"\"\n    dates = []\n    current = end_date\n    while len(dates) < n_days:\n        if current.weekday() < 5:  # 周一到周五\n            dates.append(current)\n        current -= timedelta(days=1)\n    return sorted(dates)\n\ndef detect_surge_signal(df_30min):\n    \"\"\"\n    检测急拉信号\n    条件：30分钟内涨幅 > 5%，成交量 > 前几个时段均量的5倍\n    \"\"\"\n    signals = []\n    \n    for i in range(1, len(df_30min)):\n        prev_close = df_30min.iloc[i-1]['close']\n        curr_close = df_30min.iloc[i]['close']\n        \n        # 计算涨幅\n        change_pct = (curr_close - prev_close) / prev_close * 100\n        \n        if change_pct > 5:\n            # 检查成交量\n            if i >= 2:\n                avg_volume = df_30min.iloc[:i]['volume'].mean()\n                curr_volume = df_30min.iloc[i]['volume']\n                \n                if curr_volume > avg_volume * 5:\n                    signals.append({\n                        'type': '急拉',\n                        'time_idx': i,\n                        'magnitude': change_pct\n                    })\n    \n    return signals\n\ndef detect_v_reversal(df_30min):\n    \"\"\"\n    检测V型反转信号\n    条件：30分钟跌幅 > 3%，随后连续2个30分钟K线反弹收复失地\n    \"\"\"\n    signals = []\n    \n    for i in range(1, len(df_30min) - 2):\n        prev_close = df_30min.iloc[i-1]['close']\n        drop_close = df_30min.iloc[i]['close']\n        \n        # 检测跌幅\n        drop_pct = (drop_close - prev_close) / prev_close * 100\n        \n        if drop_pct < -3:\n            # 检查后续2个K线是否收复\n            recover2_close = df_30min.iloc[i+2]['close']\n            \n            # 收复失地：收盘价回到跌幅前水平\n            if recover2_close >= prev_close * 0.98:  # 允许2%的误差\n                # 检查成交量\n                if i >= 2:\n                    avg_volume = df_30min.iloc[:i]['volume'].mean()\n                    reversal_volume = df_30min.iloc[i:i+3]['volume'].mean()\n                    \n                    if reversal_volume > avg_volume * 5:\n                        signals.append({\n                            'type': 'V型反转',\n                            'time_idx': i,\n                            'magnitude': abs(drop_pct)\n                        })\n    \n    return signals\n\ndef calculate_closing_position(daily_high, daily_low, daily_close):\n    \"\"\"计算当日收盘价位置\"\"\"\n    if daily_high == daily_low:\n        return 50.0\n    return (daily_close - daily_low) / (daily_high - daily_low) * 100\n\ndef main():\n    print(\"开始检测盘中异动信号（使用真实mootdx数据）...\")\n    print(\"=\" * 60)\n    \n    # 初始化mootdx客户端\n    client = Quotes.factory(market='std')\n    \n    # 首先探测数据可用性\n\n=== CLAUDECODE CODE ===\n#!/usr/bin/env python3\n# -*- coding: utf-8 -*-\n\"\"\"\n盘中异动信号检测 - 急拉和V型反转\n使用日K线数据近似检测（由于30分钟数据限制）\n\"\"\"\nimport sys\nsys.path.insert(0, '/Users/tomato/Documents/potato/project/YFD')\n\nfrom mootdx import quotes\nimport pandas as pd\nfrom datetime import datetime, timedelta\nimport warnings\nwarnings.filterwarnings('ignore')\n\ndef get_daily_data(code, days=30):\n    \"\"\"获取日K线数据\"\"\"\n    client = quotes.Quotes.factory(market='std')\n    try:\n        df = client.bars(symbol=code, frequency=9, offset=0)\n        if len(df) == 0:\n            return None\n\n        df.index = pd.to_datetime(df.index)\n        # 按日聚合\n        df_daily = df.resample('D').agg({\n            'open': 'first',\n            'high': 'max',\n            'low': 'min',\n            'close': 'last',\n            'volume': 'sum'\n        }).dropna()\n\n        return df_daily.tail(days)\n    except Exception as e:\n        return None\n\ndef detect_intraday_anomaly_from_daily(df):\n    \"\"\"\n    使用日K线数据近似检测盘中异动：\n    - 大振幅（high-low）/open > 8% 且收盘在上半区\n    - 成交量放大\n    \"\"\"\n    signals = []\n\n    if len(df) < 6:\n        return signals\n\n    for i in range(5, len(df)):\n        row = df.iloc[i]\n        prev_rows = df.iloc[i-5:i]\n\n        # 计算振幅\n        if row['open'] > 0:\n            amplitude = (row['high'] - row['low']) / row['open'] * 100\n\n            # 计算收盘位置\n            if row['high'] > row['low']:\n                closing_pos = (row['close'] - row['low']) / (row['high'] - row['low']) * 100\n            else:\n                closing_pos = 100.0\n\n            # 计算成交量比\n            avg_volume = prev_rows['volume'].mean()\n            if avg_volume > 0:\n                volume_ratio = row['volume'] / avg_volume\n            else:\n                volume_ratio = 1.0\n\n            # 判断急拉信号：大振幅 + 收盘在上区 + 成交量放大\n            if amplitude > 8.0 and closing_pos > 60 and volume_ratio > 3.0:\n                # 验证次日持续\n                if i < len(df) - 1:\n                    next_row = df.iloc[i+1]\n                    continuation = next_row['close'] >= row['low']\n\n                    signals.append({\n                        'date': row.name.date(),\n                        'type': '急拉',\n                        'amplitude': amplitude,\n                        'closing_position': closing_pos,\n                        'volume_ratio': volume_ratio,\n                        'continuation': continuation\n                    })\n\n            # 判断V型反转：下影线长 + 收盘在上区 + 成交量放大\n            lower_shadow = (row['close'] - row['low']) / (row['high'] - row['low']) * 100 if row['high'] > row['low'] else 0\n            if lower_shadow > 50 and closing_pos > 60 and volume_ratio > 3.0 and amplitude > 6.0:\n                if i < len(df) - 1:\n                    next_row = df.iloc[i+1]\n                    continuation = next_row['close'] >= row['low']\n\n                    #